            var updated = await ShipmentService.UpdateStatusAsync(shipmentId, newStatus);
            if (updated is not null && _shipments is not null)
            {
                var index = _shipments.FindIndex(s => s.Id == shipmentId);
                if (index >= 0) _shipments[index] = updated;
            }
        }
    }

