    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number"
                   @bind="TrackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@_isSearching">
                @if (_isSearching)
                {
                    <span class="spinner-border spinner-border-sm" role="status"></span>
                }
                else
                {
                    <span>Search</span>
                }
            </button>
        </div>
    </div>
</div>

@if (_searched && _shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number "<strong>@_searchedNumber</strong>".
    </div>
}
else if (_shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <strong>Tracking #:</strong> @_shipment.TrackingNumber
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>Origin:</strong> @_shipment.Origin</p>
                    <p><strong>Destination:</strong> @_shipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Status:</strong> <span class="badge @GetStatusBadgeClass(_shipment.Status) fs-6">@_shipment.Status</span></p>
                    <p><strong>Estimated Delivery:</strong> @(_shipment.EstimatedDelivery?.ToString("MMMM dd, yyyy") ?? "TBD")</p>
                </div>
            </div>
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(_shipment.Status)"
                         role="progressbar"
                         style="width: @(GetProgressPercent(_shipment.Status))%">
                        @_shipment.Status
                    </div>
                </div>
            </div>
        </div>
        <div class="card-footer text-muted">
            Shipped on @_shipment.CreatedAt.ToString("MMMM dd, yyyy")
        </div>
    </div>
}

@code {
    private string TrackingNumber { get; set; } = "";
    private Shipment? _shipment;
    private bool _searched;
    private bool _isSearching;
    private string _searchedNumber = "";

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(TrackingNumber)) return;
        _isSearching = true;
        _searchedNumber = TrackingNumber.Trim();
        _shipment = await ShipmentService.GetByTrackingNumberAsync(_searchedNumber);
        _searched = true;
        _isSearching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await SearchShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.PickedUp => "bg-warning text-dark",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        _ => 0
    };
}
```

### 7. Register services and add API endpoints

**Update `ShipmentTracker.Client/Program.cs`** to register the HttpClient and ShipmentHttpService:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddHttpClient<IShipmentService, ShipmentHttpService>(client =>
{
    client.BaseAddress = new Uri(builder.HostEnvironment.BaseAddress);
});

await builder.Build().RunAsync();
```

Wait — `AddHttpClient` requires `Microsoft.Extensions.Http` package. For WebAssembly, use a simpler registration:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<IShipmentService, ShipmentHttpService>();

await builder.Build().RunAsync();
```

**Update `ShipmentTracker/Program.cs`** to register the server service and add API endpoints. Add these lines:

After the Identity/auth configuration (around line 42), add:
```csharp
builder.Services.AddScoped<IShipmentService, ShipmentServerService>();
```

You'll need these usings at the top:
```csharp
using ShipmentTracker.Client.Services;
using ShipmentTracker.Services;
```

After `app.MapAdditionalIdentityEndpoints();` (around line 70), add the API endpoints:
```csharp
// Shipment API endpoints
var shipmentApi = app.MapGroup("api/shipments").RequireAuthorization();

shipmentApi.MapGet("", async (IShipmentService service) =>
    Results.Ok(await service.GetAllShipmentsAsync()));

shipmentApi.MapGet("track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
{
    var shipment = await service.GetByTrackingNumberAsync(trackingNumber);
    return shipment is null ? Results.NotFound() : Results.Ok(shipment);
}).AllowAnonymous();

shipmentApi.MapPut("{id:int}/status", async (int id, ShipmentStatus newStatus, IShipmentService service) =>
{
    var updated = await service.UpdateStatusAsync(id, newStatus);
    return updated is null ? Results.NotFound() : Results.Ok(updated);
});
```

You'll also need `using ShipmentTracker.Client.Models;` at the top for the `ShipmentStatus` enum.

