<PageTitle>Shipments Dashboard</PageTitle>

<h1>Shipments Dashboard</h1>

<div class="mb-3">
    <label for="statusFilter" class="form-label">Filter by status:</label>
    <select id="statusFilter" class="form-select w-auto d-inline-block" @bind="SelectedStatus">
        <option value="">All</option>
        @foreach (var status in Enum.GetValues<ShipmentStatus>())
        {
            <option value="@status">@status</option>
        }
    </select>
</div>

@if (_shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
