}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService : IShipmentService
{
    private readonly ApplicationDbContext _db;

    public ShipmentServerService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _db.Shipments.Select(e => MapToModel(e)).ToListAsync();
    }

    public async Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await _db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : MapToModel(entity);
    }

    public async Task<Shipment?> UpdateStatusAsync(int id, ShipmentStatus newStatus)
    {
        var entity = await _db.Shipments.FindAsync(id);
        if (entity is null) return null;
        entity.Status = newStatus;
        await _db.SaveChangesAsync();
        return MapToModel(entity);
    }

    private static Shipment MapToModel(ShipmentEntity e) => new()
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Origin = e.Origin,
        Destination = e.Destination,
        Status = e.Status,
        EstimatedDelivery = e.EstimatedDelivery,
        CustomerEmail = e.CustomerEmail,
        CreatedAt = e.CreatedAt
    };
}

