<div class="mb-3">
    <label for="statusFilter" class="form-label">Filter by status:</label>
    <select id="statusFilter" class="form-select w-auto d-inline-block" @bind="SelectedStatus">
        <option value="">All</option>
        @foreach (var status in Enum.GetValues<ShipmentStatus>())
        {
            <option value="@status">@status</option>
        }
    </select>
</div>

@if (_shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto;"
                                @onchange="(e) => OnStatusChanged(shipment.Id, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status" selected="@(status == shipment.Status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? _shipments;
    private string SelectedStatus { get; set; } = "";

    private IEnumerable<Shipment> FilteredShipments =>
        string.IsNullOrEmpty(SelectedStatus)
            ? _shipments ?? []
            : (_shipments ?? []).Where(s => s.Status.ToString() == SelectedStatus);

    protected override async Task OnInitializedAsync()
    {
        _shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task OnStatusChanged(int shipmentId, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var updated = await ShipmentService.UpdateStatusAsync(shipmentId, newStatus);
            if (updated is not null && _shipments is not null)
            {
                var index = _shipments.FindIndex(s => s.Id == shipmentId);
                if (index >= 0) _shipments[index] = updated;
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.PickedUp => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}
```

